import mysql.connector

def import_data_to_mysql(file_path, db_config, table_name):
    try:
        # Enable local_infile
        conn = mysql.connector.connect(**db_config)
        cursor = conn.cursor()
        cursor.execute("SET GLOBAL local_infile = 1;")
        
        # LOAD DATA INFILE execution
        load_data_query = "LOAD DATA INFILE '{}' INTO TABLE {}".format(file_path, table_name)
        cursor.execute(load_data_query)
        conn.commit()
        
        print(f"Data from {file_path} loaded into {table_name} successfully.")
        
    except mysql.connector.Error as err:
        print(f"Error: {err}")
    finally:
        if conn.is_connected():
            cursor.close()
            conn.close()

